import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Loader2, ImageIcon, Sparkles, Database, Trash, ArrowLeft, Tag, Eye, Edit2, Check, X
} from 'lucide-react';

// --- ESTILOS ---
const containerStyle = { padding: '40px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'sans-serif', background: '#f8fafc', minHeight: '100vh' };
const topNav = { display: 'flex', justifyContent: 'space-between', marginBottom: '30px' };
const btnBack = { background: 'none', border: 'none', color: '#64748b', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };
const sidebarTitle = { margin: 0, color: '#1e293b', display: 'flex', alignItems: 'center', gap: '12px', fontSize: '1.8rem' };
const tableWrapper = { background: 'white', borderRadius: '20px', border: '1px solid #e2e8f0', overflow: 'hidden', marginBottom: '40px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' };
const mainTable = { width: '100%', borderCollapse: 'collapse' };
const thCell = { padding: '15px', textAlign: 'left', color: '#64748b', fontSize: '0.85rem', background: '#f8fafc', borderBottom: '1px solid #e2e8f0' };
const tdCell = { padding: '10px', borderBottom: '1px solid #f1f5f9' };
const inputTable = { width: '100%', border: 'none', outline: 'none', padding: '10px', background: 'transparent', fontSize: '0.9rem' };
const btnNuevaSucursalCustom = { background: '#1e293b', color: 'white', padding: '12px 25px', borderRadius: '12px', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };
const editInput = { width: '100%', padding: '5px', borderRadius: '4px', border: '1px solid #e2e8f0', marginBottom: '5px', fontSize: '0.8rem' };

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();
  const API_URL = "http://localhost:5000"; 
  const CLOUD_NAME = "dwpgncjgn";

  const filaNueva = () => ({
    id: Date.now() + Math.random(),
    producto: '', precioNuevo: '', precioViejo: '', stock: '', categoria: 'Almacén', fotoSugerida: null
  });

  const [filas, setFilas] = useState([filaNueva()]);
  const [publicados, setPublicados] = useState([]);
  const [galeria, setGaleria] = useState([]);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [cargando, setCargando] = useState(false);
  
  // Estado para controlar qué producto se está editando
  const [editandoId, setEditandoId] = useState(null);
  const [datosEdit, setDatosEdit] = useState({});

  const cargarPublicados = useCallback(async () => {
    try {
      const res = await axios.get(`${API_URL}/api/ofertas/local/${localId}`);
      setPublicados(res.data);
    } catch (e) { console.error("Error cargando publicados", e); }
  }, [API_URL, localId]);

  useEffect(() => {
    cargarPublicados();
    axios.get(`${API_URL}/api/galeria`).then(res => setGaleria(res.data)).catch(err => console.log(err));
  }, [cargarPublicados]);

  const buscarMatch = (texto) => {
    if (!texto || texto.length < 3) return null;
    const t = texto.toLowerCase();
    const palabras = t.split(' ').filter(p => p.length > 1);
    return galeria.find(f => palabras.every(p => f.nombreReferencia.includes(p)));
  };

  const handlePaste = (e) => {
    e.preventDefault();
    const data = e.clipboardData.getData('Text');
    const lineas = data.split('\n').filter(line => line.trim() !== '');
    const nuevas = lineas.map(line => {
        const celdas = line.split('\t');
        return { ...filaNueva(), id: Math.random(), producto: celdas[0] || '', precioNuevo: celdas[1] || '', precioViejo: celdas[2] || '', stock: celdas[3] || 0, categoria: celdas[4] || 'Almacén', fotoSugerida: buscarMatch(celdas[0]) };
    });
    setFilas(nuevas);
  };

  const publicarOfertas = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Selecciona fechas.");
    setCargando(true);
    try {
      const promesas = filas.map(f => {
        if (!f.producto || !f.precioNuevo) return null;
        return axios.post(`${API_URL}/api/ofertas`, {
          producto: f.producto, precioNuevo: Number(f.precioNuevo), precioViejo: Number(f.precioViejo || f.precioNuevo),
          stock: Number(f.stock), publicId: f.fotoSugerida ? f.fotoSugerida.publicId : 'placeholder_id',
          local: localId, categoria: f.categoria, publicado: true, fechaInicioOferta: fechas.inicio, fechaFinOferta: fechas.fin
        });
      });
      await Promise.all(promesas.filter(p => p !== null));
      setFilas([filaNueva()]);
      cargarPublicados();
    } catch (e) { alert("Error al publicar."); } finally { setCargando(false); }
  };

  const eliminarOferta = async (id) => {
    if(!window.confirm("¿Eliminar publicación?")) return;
    try {
      await axios.delete(`${API_URL}/api/ofertas/${id}`);
      cargarPublicados();
    } catch (e) { alert("Error"); }
  };

  // FUNCIONES DE EDICIÓN INDIVIDUAL
  const iniciarEdicion = (prod) => {
    setEditandoId(prod._id);
    setDatosEdit({ ...prod });
  };

  const guardarCambios = async () => {
    try {
      await axios.put(`${API_URL}/api/ofertas/${editandoId}`, datosEdit);
      setEditandoId(null);
      cargarPublicados();
    } catch (e) { alert("Error al actualizar"); }
  };

  return (
    <div style={containerStyle}>
      {/* HEADER E INPUTS DE CARGA (Igual que antes) */}
      <div style={topNav}>
        <button onClick={() => navigate(-1)} style={btnBack}><ArrowLeft size={18}/> Dashboard</button>
        <button style={{...btnNuevaSucursalCustom, background: 'rgba(230, 126, 34, 0.1)', color: '#e67e22', border: '1px solid #e67e22'}}><Database size={16}/> Galería</button>
      </div>

      <div style={{marginBottom: '30px'}}><h1 style={sidebarTitle}><Tag color="#e67e22"/> Editor de Inventario</h1></div>

      <div style={tableWrapper} onPaste={handlePaste}>
        {/* ... Tabla de carga masiva ... */}
        <table style={mainTable}>
          <thead><tr><th style={thCell}>Foto</th><th style={thCell}>Producto</th><th style={thCell}>P. Nuevo</th><th style={thCell}>P. Viejo</th><th style={thCell}>Stock</th><th style={thCell}></th></tr></thead>
          <tbody>
            {filas.map(f => (
              <tr key={f.id}><td style={tdCell}>{f.fotoSugerida ? <img src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_50,c_fill/v1/${f.fotoSugerida.publicId}`} style={{borderRadius:'8px'}} alt="p"/> : <ImageIcon color="#cbd5e1"/>}</td>
              <td style={tdCell}><input style={inputTable} value={f.producto} onChange={e => {const n = [...filas]; n[n.findIndex(x=>x.id===f.id)].producto=e.target.value; n[n.findIndex(x=>x.id===f.id)].fotoSugerida=buscarMatch(e.target.value); setFilas(n);}}/></td>
              <td style={tdCell}><input style={inputTable} value={f.precioNuevo} onChange={e => {const n = [...filas]; n[n.findIndex(x=>x.id===f.id)].precioNuevo=e.target.value; setFilas(n);}}/></td>
              <td style={tdCell}><input style={inputTable} value={f.precioViejo} onChange={e => {const n = [...filas]; n[n.findIndex(x=>x.id===f.id)].precioViejo=e.target.value; setFilas(n);}}/></td>
              <td style={tdCell}><input style={inputTable} value={f.stock} onChange={e => {const n = [...filas]; n[n.findIndex(x=>x.id===f.id)].stock=e.target.value; setFilas(n);}}/></td>
              </tr>
            ))}
          </tbody>
        </table>
        <div style={{padding: '20px', background: '#f8fafc', display: 'flex', justifyContent: 'space-between'}}>
            <div style={{display:'flex', gap:'10px'}}><input type="date" onChange={e => setFechas({...fechas, inicio: e.target.value})} /><input type="date" onChange={e => setFechas({...fechas, fin: e.target.value})} /></div>
            <button onClick={publicarOfertas} disabled={cargando} style={btnNuevaSucursalCustom}>{cargando ? <Loader2 className="animate-spin"/> : <Sparkles/>} Publicar</button>
        </div>
      </div>

      {/* SECCIÓN DE PRODUCTOS PUBLICADOS CON EDICIÓN INDIVIDUAL */}
      <div style={{marginTop: '20px'}}>
        <h2 style={{...sidebarTitle, fontSize: '1.4rem', marginBottom: '20px'}}><Eye color="#1e293b" size={24}/> Productos Activos</h2>
        <div style={{display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))', gap: '20px'}}>
          {publicados.map(p => (
            <div key={p._id} style={{background: 'white', padding: '15px', borderRadius: '20px', border: editandoId === p._id ? '2px solid #e67e22' : '1px solid #e2e8f0', position: 'relative'}}>
              
              {/* Botones de acción arriba */}
              <div style={{position:'absolute', top:'10px', right:'10px', display:'flex', gap:'5px'}}>
                {editandoId === p._id ? (
                  <>
                    <button onClick={guardarCambios} style={{background:'#dcfce7', color:'#16a34a', border:'none', borderRadius:'50%', width:'30px', height:'30px', cursor:'pointer'}}><Check size={16}/></button>
                    <button onClick={() => setEditandoId(null)} style={{background:'#f1f5f9', color:'#64748b', border:'none', borderRadius:'50%', width:'30px', height:'30px', cursor:'pointer'}}><X size={16}/></button>
                  </>
                ) : (
                  <>
                    <button onClick={() => iniciarEdicion(p)} style={{background:'#fef3c7', color:'#d97706', border:'none', borderRadius:'50%', width:'30px', height:'30px', cursor:'pointer'}}><Edit2 size={14}/></button>
                    <button onClick={() => eliminarOferta(p._id)} style={{background:'#fee2e2', color:'#ef4444', border:'none', borderRadius:'50%', width:'30px', height:'30px', cursor:'pointer'}}><Trash size={14}/></button>
                  </>
                )}
              </div>

              <img src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_200,h_130,c_fill/v1/${p.publicId}`} style={{width:'100%', height:'110px', objectFit:'cover', borderRadius:'12px', marginBottom:'10px', opacity: editandoId === p._id ? 0.5 : 1}} alt={p.producto}/>
              
              {editandoId === p._id ? (
                <div>
                  <input style={editInput} value={datosEdit.producto} onChange={e => setDatosEdit({...datosEdit, producto: e.target.value})} placeholder="Nombre"/>
                  <div style={{display:'flex', gap:'5px'}}>
                    <input style={editInput} type="number" value={datosEdit.precioNuevo} onChange={e => setDatosEdit({...datosEdit, precioNuevo: e.target.value})} placeholder="Nuevo $"/>
                    <input style={editInput} type="number" value={datosEdit.precioViejo} onChange={e => setDatosEdit({...datosEdit, precioViejo: e.target.value})} placeholder="Viejo $"/>
                  </div>
                  <input style={editInput} type="number" value={datosEdit.stock} onChange={e => setDatosEdit({...datosEdit, stock: e.target.value})} placeholder="Stock"/>
                </div>
              ) : (
                <>
                  <h4 style={{margin: '0', fontSize: '0.95rem', color: '#1e293b'}}>{p.producto}</h4>
                  <div style={{display:'flex', gap:'8px', alignItems:'center', marginTop: '8px'}}>
                    <span style={{fontWeight:'bold', color:'#e67e22'}}>${p.precioNuevo}</span>
                    <span style={{textDecoration:'line-through', color:'#94a3b8', fontSize:'0.75rem'}}>${p.precioViejo}</span>
                  </div>
                  <p style={{fontSize:'0.75rem', color:'#64748b', marginTop:'4px'}}>Stock: {p.stock} | {p.categoria}</p>
                </>
              )}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default GestionOfertas;
